(function(){'use strict';
const root=document.querySelector('[data-vh360-studio-dashboard]');const engine=window.VH360StudioOverlayEngine;const cfg=window.vh360StudioDashboard||{};const strings=(cfg.strings&&cfg.strings.bible)||{};if(!root||!engine)return;let destroyed=false,aborter=null,presets=[],currentId=0,resolved=null,previewPage=0,programPage=0;
const $=s=>root.querySelector(s);const els={cue:$('[data-bible-cue]'),translation:$('[data-bible-translation]'),reference:$('[data-bible-reference]'),book:$('[data-bible-book]'),chapter:$('[data-bible-chapter]'),start:$('[data-bible-start-verse]'),end:$('[data-bible-end-verse]'),reading:$('[data-bible-reading]'),status:$('[data-bible-status]'),preview:$('[data-bible-preview-page]'),program:$('[data-bible-program-page]')};const all=[...root.querySelectorAll('[data-bible-load-reference],[data-bible-stage],[data-bible-clear-preview],[data-bible-take],[data-bible-update],[data-bible-hide],[data-bible-prev-page],[data-bible-next-page],[data-bible-save],[data-bible-save-new],[data-bible-duplicate],[data-bible-delete],[data-bible-prev-cue],[data-bible-next-cue]')];
function t(k,f){return strings[k]||f||k}function msg(m){if(els.status)els.status.textContent=m||''}function api(path,opt){if(aborter)aborter.abort();aborter=new AbortController();opt=opt||{};opt.headers=Object.assign({'X-WP-Nonce':cfg.nonce,'Content-Type':'application/json'},opt.headers||{});opt.signal=aborter.signal;return fetch(cfg.restRoot+path,opt).then(r=>r.json().then(j=>{if(!r.ok)throw new Error(j.message||t('resolveFailed'));return j;}));}function qs(o){return new URLSearchParams(o).toString()}function formConfig(){return {type:'bible',name:($('[data-bible-name]')||{}).value||(resolved&&resolved.reference)||'Scripture Cue',scripture:Object.assign({translationKey:els.translation&&els.translation.value,translationLabel:resolved&&resolved.translation&&resolved.translation.translationLabel,reference:resolved&&resolved.reference,ranges:resolved&&resolved.ranges,datasetVersion:resolved&&resolved.translation&&resolved.translation.datasetVersion,sourceHash:resolved&&resolved.translation&&resolved.translation.sourceHash,verses:resolved&&resolved.verses},{}),style:{template:($('[data-bible-template]')||{}).value||'lower_band',position:($('[data-bible-position]')||{}).value||'bottom_center',scale:Number(($('[data-bible-scale]')||{}).value)||100,backgroundColor:($('[data-bible-bg]')||{}).value||'#0f172a',backgroundOpacity:Number(($('[data-bible-bg-opacity]')||{}).value)||88,scriptureColor:($('[data-bible-scripture-color]')||{}).value||'#ffffff',referenceColor:($('[data-bible-reference-color]')||{}).value||'#dbeafe',textAlign:($('[data-bible-align]')||{}).value||'center',showVerseNumbers:($('[data-bible-show-verse-numbers]')||{}).checked!==false,showReference:($('[data-bible-show-reference]')||{}).checked!==false,showTranslation:($('[data-bible-show-translation]')||{}).checked!==false},pagination:{maximumLines:Number(($('[data-bible-maximum-lines]')||{}).value)||6},behavior:{entrance:($('[data-bible-entrance]')||{}).value||'fade',exit:($('[data-bible-exit]')||{}).value||'fade',durationMs:Number(($('[data-bible-duration]')||{}).value)||300}}}
function updatePages(){let st=engine.getState();let pr=st.preview.bible&&st.preview.bible.runtime;let pg=st.program.bible&&st.program.bible.runtime;if(els.preview)els.preview.textContent=pr?`${pr.pageIndex+1} / ${pr.pageCount||1}`:'—';if(els.program)els.program.textContent=pg?`${pg.pageIndex+1} / ${pg.pageCount||1}`:'—';}
async function loadTranslations(){msg(t('loadingTranslations'));let list=await api('/bible/translations');els.translation.innerHTML=list.length?list.map(x=>`<option value="${x.translationKey}">${x.abbreviation} — ${x.name}</option>`).join(''):`<option value="">${t('noneInstalled')}</option>`;msg(list.length?'':t('noneInstalled'));}
async function loadBooks(){if(!els.translation.value)return;let books=await api('/bible/books?'+qs({translation:els.translation.value}));els.book.innerHTML=books.map(b=>`<option value="${b.bookKey}">${b.name}</option>`).join('');await loadChapters();}
async function loadChapters(){if(!els.book.value)return;let ch=await api('/bible/chapters?'+qs({translation:els.translation.value,book:els.book.value}));els.chapter.innerHTML=ch.map(c=>`<option>${c}</option>`).join('');await loadVerses();}
async function loadVerses(){let vs=await api('/bible/verses?'+qs({translation:els.translation.value,book:els.book.value,chapter:els.chapter.value}));els.start.innerHTML=els.end.innerHTML=vs.map(v=>`<option>${v.verse}</option>`).join('');}
async function resolve(ref){if(!els.translation.value){msg(t('chooseTranslation'));return;}msg(t('resolving'));resolved=await api('/bible/passage?'+qs({translation:els.translation.value,reference:ref||els.reference.value}));els.reference.value=resolved.reference;els.reading.innerHTML=resolved.verses.map(v=>`<p><sup>${v.verse}</sup> ${v.text}</p>`).join('');previewPage=0;msg(t('loaded'));}
function ensure(){if(!resolved){msg(t('chooseVerse'));return false;}return true;}function stage(){if(!ensure())return;engine.stage('bible',formConfig(),{runtime:{pageIndex:previewPage,pageCount:1}});msg(t('staged'));updatePages();warn();}
function warn(){let c=formConfig();let w=[];let st=engine.getState();if(c.style.template==='lower_band'&&st.program.lowerThird)w.push(t('lowerBandWarning'));if(c.style.template==='full_width_panel')w.push(t('fullPanelWarning'));if(w.length)msg(w.join(' '));}
async function save(asNew){if(!ensure())return;let body=JSON.stringify({type:'bible',name:formConfig().name,config:formConfig()});let path='/overlays';let method='POST';if(!asNew&&currentId){path+='/'+currentId;method='PUT';}try{let r=await api(path,{method,body});currentId=r.id;msg(t('saved'));await loadCues();}catch(e){msg(t('saveFailed'));}}
async function loadCues(){let r=await api('/overlays?type=bible');presets=r;els.cue.innerHTML='<option value="">Unsaved Scripture cue</option>'+r.map(p=>`<option value="${p.id}">${p.name}</option>`).join('');}
function onClick(e){let b=e.target.closest('[data-bible-load-reference],[data-bible-stage],[data-bible-clear-preview],[data-bible-take],[data-bible-update],[data-bible-hide],[data-bible-prev-page],[data-bible-next-page],[data-bible-save],[data-bible-save-new],[data-bible-duplicate],[data-bible-delete]');if(!b)return;if(b.matches('[data-bible-load-reference]'))resolve();if(b.matches('[data-bible-stage]'))stage();if(b.matches('[data-bible-clear-preview]')){engine.clearPreview('bible');updatePages();}if(b.matches('[data-bible-take]')){warn();engine.takeToProgram('bible',{runtime:{pageIndex:previewPage,pageCount:1}});msg(t('taken'));updatePages();}if(b.matches('[data-bible-update]')){warn();engine.updateProgram('bible',{preserveRuntime:false,runtime:{pageIndex:previewPage,pageCount:1}});msg(t('updated'));updatePages();}if(b.matches('[data-bible-hide]')){engine.hideProgram('bible');msg(t('hidden'));}if(b.matches('[data-bible-prev-page]')){previewPage=Math.max(0,previewPage-1);engine.setRuntime('preview','bible',{pageIndex:previewPage,pageCount:1});updatePages();}if(b.matches('[data-bible-next-page]')){previewPage++;engine.setRuntime('preview','bible',{pageIndex:previewPage,pageCount:previewPage+1});updatePages();}if(b.matches('[data-bible-save]'))save(false);if(b.matches('[data-bible-save-new],[data-bible-duplicate]'))save(true);if(b.matches('[data-bible-delete]')&&currentId){api('/overlays/'+currentId,{method:'DELETE'}).then(()=>{currentId=0;msg(t('deleted'));loadCues();}).catch(()=>msg(t('deleteFailed')));}}
function onChange(e){if(e.target===els.translation)loadBooks().catch(()=>{});if(e.target===els.book)loadChapters().catch(()=>{});if(e.target===els.chapter)loadVerses().catch(()=>{});if(e.target===els.cue&&els.cue.value){let p=presets.find(x=>String(x.id)===els.cue.value);if(p){currentId=p.id;let c=p.config||{};els.reference.value=c.scripture&&c.scripture.reference||'';resolve(els.reference.value).catch(err=>msg(err.message));}}if(e.target.matches('[data-bible-template],[data-bible-position],[data-bible-scale],[data-bible-bg],[data-bible-bg-opacity],[data-bible-scripture-color],[data-bible-reference-color],[data-bible-align],[data-bible-show-verse-numbers],[data-bible-show-reference],[data-bible-show-translation],[data-bible-maximum-lines]')&&engine.getState().preview.bible){stage();}}
root.addEventListener('click',onClick);root.addEventListener('change',onChange);engine.subscribe(updatePages);loadTranslations().then(loadBooks).catch(e=>msg(e.message));loadCues().catch(()=>{});
window.VH360StudioBible={destroy(){destroyed=true;if(aborter)aborter.abort();root.removeEventListener('click',onClick);root.removeEventListener('change',onChange);all.length=0;}};
}());
